// Оборачиваем проверенный текст в JSON-формат для Literary Editor
const factCheckedText = $input.first().json.choices[0].message.content;
const webhookBody = $('Webhook').first().json.body;

const wrappedInput = {
  phase: 'A',
  project_id: String(webhookBody.draft_id || webhookBody.telegram_id),
  book_text: {
    chapters: [
      {
        id: 'ch_01',
        title: 'Глава 1',
        content: factCheckedText
      }
    ],
    callouts: [],
    historical_notes: []
  }
};

return [{ json: { wrapped_input: JSON.stringify(wrappedInput) } }];

// Извлекаем текст из ответа Literary Editor (JSON или plain text)
const rawContent = $input.first().json.choices[0].message.content;

let extracted_text = rawContent;

try {
  const cleaned = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  const parsed = JSON.parse(cleaned);
  if (parsed.chapters && parsed.chapters.length > 0) {
    extracted_text = parsed.chapters.map(ch => ch.content || '').join('\n\n');
  }
} catch (e) {
  extracted_text = rawContent;
}

return [{ json: { extracted_text } }];

// Оборачиваем текст Literary Editor в JSON-формат для Proofreader
const literaryText = $input.first().json.extracted_text;
const webhookBody = $('Webhook').first().json.body;

const wrappedInput = {
  phase: 'A',
  project_id: String(webhookBody.draft_id || webhookBody.telegram_id),
  book_text: {
    chapters: [
      {
        id: 'ch_01',
        title: 'Глава 1',
        content: literaryText
      }
    ],
    callouts: [],
    historical_notes: []
  }
};

return [{ json: { wrapped_input: JSON.stringify(wrappedInput) } }];

// Извлекаем текст из JSON-ответа Proofreader
const rawContent = $input.first().json.choices[0].message.content;

let bio_text = rawContent;
let style_passport = null;
let corrections_count = 0;

try {
  const cleaned = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  const parsed = JSON.parse(cleaned);

  if (parsed.chapters && parsed.chapters.length > 0) {
    bio_text = parsed.chapters.map(ch => ch.content || '').join('\n\n');
  }

  style_passport = parsed.style_passport || null;
  corrections_count = (parsed.summary && parsed.summary.total_corrections) ? parsed.summary.total_corrections : 0;
} catch (e) {
  bio_text = rawContent;
}

return [{ json: { bio_text, style_passport, corrections_count } }];

// Извлекаем вопросы из JSON-ответа Interview Architect (или plain text)
const rawContent = $input.first().json.choices[0].message.content;

let questions_text = rawContent;

try {
  const cleaned = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  const parsed = JSON.parse(cleaned);

  const allQuestions = [];

  // Формат: {questions: [{text: '...', category: '...'}, ...]}
  if (parsed.questions && parsed.questions.length > 0) {
    parsed.questions.forEach((q, i) => {
      const qText = q.text || q.question || q;
      allQuestions.push(`${i + 1}. ${qText}`);
    });
  }
  // Формат: {question_groups: [{questions: [...]}, ...]}
  else if (parsed.question_groups && parsed.question_groups.length > 0) {
    let idx = 1;
    parsed.question_groups.forEach(group => {
      (group.questions || []).forEach(q => {
        const qText = q.text || q.question || q;
        allQuestions.push(`${idx}. ${qText}`);
        idx++;
      });
    });
  }

  if (allQuestions.length > 0) {
    questions_text = allQuestions.join('\n');
  }
} catch (e) {
  questions_text = rawContent;
}

return [{ json: { questions_text } }];
